import{_ as s,H as e,f as r,i as n}from"./chunks/framework.BHvCMIhP.js";const g=JSON.parse('{"title":"lexer 生成器 vs 手写","description":"","frontmatter":{},"headers":[],"relativePath":"../interpreterLearning/06-lexer生成器vs手写.md","filePath":"../interpreterLearning/06-lexer生成器vs手写.md","lastUpdated":1778496697000}'),a={name:"../interpreterLearning/06-lexer生成器vs手写.md"};function o(i,t,l,d,c,p){return e(),r("div",null,[...t[0]||(t[0]=[n(`<h1 id="lexer-生成器-vs-手写" tabindex="-1">lexer 生成器 vs 手写 <a class="header-anchor" href="#lexer-生成器-vs-手写" aria-label="Permalink to &quot;lexer 生成器 vs 手写&quot;">​</a></h1><p>打开任何编译原理教材,讲完正则就会推荐你用 lex / flex / re2c——「写 BNF,工具帮你生成 lexer,<strong>比手写严谨</strong>」。可是你打开 V8、CPython、rustc、Go、TypeScript、Roslyn 的源码,<strong>全部手写</strong>。<strong>这不是因为他们老派,是因为生成器在生产语言场景下烂得几乎用不了</strong>。这一篇拆清楚为什么——读完你会明白,<strong>手写 lexer 不是&quot;原始&quot;,而是&quot;工业一线的必经之路&quot;</strong>。</p><blockquote><p>一句话先记住:<strong>lex / flex 在 1970s 的 Unix 工具里很好,在 2020s 的生产编译器里很差</strong>——错误信息控不住、性能不够、上下文不敏感、增量不友好。<strong>ANTLR 在 DSL / SQL 方言里还有市场,主流编程语言全是手写</strong>。Mochi 跟一线节奏,<strong>全程手写,不用生成器</strong>。</p></blockquote><hr><h2 id="一、生成器在做什么" tabindex="-1">一、生成器在做什么 <a class="header-anchor" href="#一、生成器在做什么" aria-label="Permalink to &quot;一、生成器在做什么&quot;">​</a></h2><p><code>lex</code> / <code>flex</code> 接受一份「正则 → 动作」的规则文件——<code>&quot;let&quot; { return LET; }</code>、<code>[0-9]+ { return NUM; }</code>、<code>[a-zA-Z_]\\w* { return IDENT; }</code>,几十行覆盖一门小语言。flex 把规则<strong>编译成一个巨大的 DFA</strong>,生成 C 代码——一个 <code>yylex()</code> 函数。<strong>理论上很美</strong>:正则等价于 DFA,Thompson 构造法保证最长匹配 + 最优顺序——<strong>写规则即写实现</strong>。</p><p><code>re2c</code> 同思路但更现代,生成代码可读,<strong>PHP / ninja / Hack 都用它</strong>。<code>ANTLR</code> 更激进——同时生成 lexer + parser,<strong>Hive / Presto / Spark SQL 都是</strong>。</p><hr><h2 id="二、理论上应该用工具" tabindex="-1">二、理论上应该用工具 <a class="header-anchor" href="#二、理论上应该用工具" aria-label="Permalink to &quot;二、理论上应该用工具&quot;">​</a></h2><p>教科书的论据:</p><ol><li>正则 ≡ NFA ≡ DFA(Kleene 定理)</li><li>DFA 是 O(1) 状态转移,<strong>理论最优</strong></li><li>规则即文档,改语言只改规则</li><li>工具帮你查歧义、查不可达规则</li></ol><p><strong>如果你做学术玩具,这些都对</strong>。问题是生产语言的需求<strong>几乎没有一条</strong>能从这些性质里推出来。</p><hr><h2 id="三、为什么-v8-cpython-rustc-全是手写" tabindex="-1">三、为什么 V8 / CPython / rustc 全是手写 <a class="header-anchor" href="#三、为什么-v8-cpython-rustc-全是手写" aria-label="Permalink to &quot;三、为什么 V8 / CPython / rustc 全是手写&quot;">​</a></h2><h3 id="_3-1-错误信息" tabindex="-1">3.1 错误信息 <a class="header-anchor" href="#_3-1-错误信息" aria-label="Permalink to &quot;3.1 错误信息&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>flex 默认报错: syntax error at line 5</span></span>
<span class="line"><span>rustc 报错:</span></span>
<span class="line"><span>error: unknown character \`@\`</span></span>
<span class="line"><span> --&gt; src/main.rs:5:13</span></span>
<span class="line"><span>  |</span></span>
<span class="line"><span>5 |     let x @ = 10;</span></span>
<span class="line"><span>  |           ^ help: did you mean \`=\`?</span></span></code></pre></div><p><strong>rustc 这样的错误信息,生成器写不出来</strong>。flex 的错误处理只能 print 一行——你要带列号、高亮、建议、相邻 token 上下文,<strong>必须手写</strong>。</p><h3 id="_3-2-性能" tabindex="-1">3.2 性能 <a class="header-anchor" href="#_3-2-性能" aria-label="Permalink to &quot;3.2 性能&quot;">​</a></h3><p>V8 的 scanner 走模板特化 + ASCII fast path + 字符分类查表——<strong>比 regex 引擎快 3-5 倍</strong>。flex 生成的 DFA 状态转移虽然 O(1),但<strong>常数大</strong>:每个字符要查 256 大小的表,缓存不友好。</p><p>手写允许:</p><ul><li>SIMD 一次扫 16 字节找终止符</li><li>跳过空白用 <code>memchr</code> 加速</li><li>关键字用 perfect hash 不走 strcmp</li></ul><h3 id="_3-3-上下文敏感" tabindex="-1">3.3 上下文敏感 <a class="header-anchor" href="#_3-3-上下文敏感" aria-label="Permalink to &quot;3.3 上下文敏感&quot;">​</a></h3><p>JS 里 <code>/</code> 是除号还是正则字面量?<strong>取决于上一个 token</strong>:</p><div class="language-javascript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">a </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> b           </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 除号</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">return</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /</span><span style="--shiki-light:#032F62;--shiki-dark:#DBEDFF;">b</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">g</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     // 正则</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">typeof</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> /</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">b</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      // 正则</span></span></code></pre></div><p>flex / re2c 是无状态 DFA,<strong>做不了</strong>。V8 的 scanner 维护一个 <code>last_token_was_expression</code>,<strong>手动判断</strong>。</p><p>Python 的缩进更狠——<strong>INDENT / DEDENT 是 token,词法层就要做栈</strong>。Rust 的 raw string <code>r###&quot;...&quot;###</code> 里 <code>#</code> 的数量要匹配——<strong>这不是正则能描述的语言</strong>,必须手写。</p><h3 id="_3-4-增量解析-lsp" tabindex="-1">3.4 增量解析 / LSP <a class="header-anchor" href="#_3-4-增量解析-lsp" aria-label="Permalink to &quot;3.4 增量解析 / LSP&quot;">​</a></h3><p>LSP 场景:你改了一个字符,IDE 想 <strong>只重新分析改动周围</strong>,不重扫整个文件。<strong>flex 做不了</strong>——它是一次性扫到底。</p><p>rustc 的 lexer 设计成「以 token 为单位增量产出」,IDE 从光标位置往回找一个安全点重 tokenize。<strong>这是手写才能做到的事</strong>。</p><hr><h2 id="四、对比-真实选型" tabindex="-1">四、对比 + 真实选型 <a class="header-anchor" href="#四、对比-真实选型" aria-label="Permalink to &quot;四、对比 + 真实选型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>lex/flex</th><th>re2c</th><th>ANTLR</th><th>手写</th></tr></thead><tbody><tr><td>写规则速度</td><td>快</td><td>快</td><td>快</td><td>慢</td></tr><tr><td>错误信息</td><td>烂</td><td>烂</td><td>一般</td><td><strong>可控</strong></td></tr><tr><td>性能</td><td>一般</td><td>好</td><td>一般</td><td><strong>最好</strong></td></tr><tr><td>上下文敏感</td><td>不行</td><td>勉强</td><td>可以但代码丑</td><td><strong>自然</strong></td></tr><tr><td>增量解析</td><td>不行</td><td>不行</td><td>不行</td><td><strong>可以</strong></td></tr><tr><td>适合</td><td>小工具、配置</td><td>嵌入 C 项目</td><td>DSL / SQL</td><td>生产编程语言</td></tr></tbody></table><table tabindex="0"><thead><tr><th>项目</th><th>lexer</th><th>文件</th></tr></thead><tbody><tr><td>V8</td><td>手写 C++</td><td><code>v8/src/parsing/scanner.cc</code></td></tr><tr><td>CPython</td><td>手写 C</td><td><code>Parser/tokenizer.c</code></td></tr><tr><td>rustc</td><td>手写 Rust</td><td><code>compiler/rustc_lexer/src/lib.rs</code></td></tr><tr><td>Go</td><td>手写 Go</td><td><code>src/go/scanner/scanner.go</code></td></tr><tr><td>TypeScript</td><td>手写 TS</td><td><code>src/compiler/scanner.ts</code></td></tr><tr><td>Roslyn(C#)</td><td>手写 C#</td><td><code>Microsoft.CodeAnalysis.CSharp.Lexer</code></td></tr><tr><td>Lua</td><td>手写 C</td><td><code>lua/llex.c</code>(500 行,极小)</td></tr><tr><td>PHP</td><td>re2c</td><td>历史包袱</td></tr><tr><td>Hive QL</td><td>ANTLR</td><td>DSL 场景</td></tr><tr><td>PostgreSQL</td><td>flex</td><td>老 + SQL 文法规整</td></tr></tbody></table><p><strong>模式很清楚</strong>:<strong>编程语言全是手写,SQL / DSL 还有生成器</strong>——因为 SQL 错误信息要求低、文法规整、性能不敏感。</p><hr><h2 id="五、antlr-在-dsl-场景下还是值钱" tabindex="-1">五、ANTLR 在 DSL 场景下还是值钱 <a class="header-anchor" href="#五、antlr-在-dsl-场景下还是值钱" aria-label="Permalink to &quot;五、ANTLR 在 DSL 场景下还是值钱&quot;">​</a></h2><p>不要因为 V8 手写就一刀切。<strong>做 DSL / 规则引擎 / 配置语言</strong>,大概率用 ANTLR:</p><ul><li>文法清晰可读(Hive 几百条 grammar 一目了然)</li><li>AST 自动生成,parser 也省</li><li>多语言后端(同一份语法生成 Java + Python + TS)</li><li>错误恢复在 ANTLR 4 已经做得不差</li></ul><p><strong>判断标准</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户期待 IDE 体验、增量解析、精确错误高亮?  → 手写</span></span>
<span class="line"><span>用户只在 CLI 跑、错误信息能用就行?          → ANTLR / flex</span></span></code></pre></div><p>Mochi 的目标是模拟生产语言,<strong>所以手写</strong>。你做内部规则引擎,<strong>别为了&quot;工业感&quot;也手写,白浪费时间</strong>。</p><hr><h2 id="六、mochi-这里偷懒了" tabindex="-1">六、Mochi 这里偷懒了 <a class="header-anchor" href="#六、mochi-这里偷懒了" aria-label="Permalink to &quot;六、Mochi 这里偷懒了&quot;">​</a></h2><ul><li><strong>没写 fuzzer 验证 lexer 正确性</strong> —— 生产 lexer 都有 100k+ AFL fuzz case</li><li><strong>不支持 UTF-8 多字节标识符</strong> —— 工业必备,要做 Unicode 表</li><li><strong>没做增量 tokenize</strong> —— LSP 才需要,30 篇才提</li><li><strong>错误信息没有 source span 高亮</strong> —— 15 篇会补</li><li><strong>没做 SIMD 加速</strong> —— 学习版没必要</li></ul><p><strong>学完原理,真要做生产 lexer</strong>,回头看 rustc <code>compiler/rustc_lexer/src/cursor.rs</code> 那 80 行——<strong>比这一篇值钱 10 倍</strong>。</p><hr><h2 id="七、工业指针" tabindex="-1">七、工业指针 <a class="header-anchor" href="#七、工业指针" aria-label="Permalink to &quot;七、工业指针&quot;">​</a></h2><p>最值得逐行读的手写 lexer:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>rustc:       compiler/rustc_lexer/src/lib.rs        (~700 行, 极干净)</span></span>
<span class="line"><span>             compiler/rustc_lexer/src/cursor.rs    (~80 行, peek/advance 范本)</span></span>
<span class="line"><span>Go:          src/go/scanner/scanner.go             (~800 行, 含 semicolon 自动插入)</span></span>
<span class="line"><span>Lua:         lua/llex.c                            (~500 行, 极简单纯粹)</span></span>
<span class="line"><span>TypeScript:  src/compiler/scanner.ts               (~2700 行, 案例丰富)</span></span>
<span class="line"><span>V8:          src/parsing/scanner.cc                (~1200 行, 性能优化范本)</span></span></code></pre></div><p><strong>别先读 CPython <code>Parser/tokenizer.c</code></strong>——里面有 Python 缩进的特殊处理,<strong>新手会以为&quot;词法都这么复杂&quot;</strong>,其实不是。</p><hr><h2 id="八、踩坑提醒" tabindex="-1">八、踩坑提醒 <a class="header-anchor" href="#八、踩坑提醒" aria-label="Permalink to &quot;八、踩坑提醒&quot;">​</a></h2><ol><li><strong>学校教 lex / flex,工作中没人用</strong> —— 别拿&quot;我会 lex&quot;当本事</li><li><strong>学正则有用,但不是写 lexer 用</strong> —— 学完去写 sed / grep / 表单校验</li><li><strong>DSL 直接上 ANTLR 没问题</strong> —— 别为了&quot;工程感&quot;也手写</li><li><strong>手写不等于不严谨</strong> —— rustc 比生成器还规整,因为 test case 比规则多</li><li><strong>以为正则能解析所有语言</strong> —— Rust raw string、Python f-string 都不是正则</li><li><strong>以为生成器代码可读</strong> —— flex 生成的 <code>yylex</code> 函数你打开就懵</li><li><strong>想用 ANTLR 但把整个生产语言文法拷过来</strong> —— 体量 ANTLR 跑不动</li><li><strong>觉得手写就要重新发明 peek / advance</strong> —— 抄 <code>rustc_lexer/cursor.rs</code>,80 行就够</li></ol><hr><p>下一篇:<code>07-文法基础.md</code>,从 BNF 起步——<strong>LL vs LR、二义性、运算符优先级</strong>,看完你才能理解为什么递归下降是工程主流、为什么 yacc / bison 没人用了。</p>`,55)])])}const u=s(a,[["render",o]]);export{g as __pageData,u as default};
